7000	\begin{definition}[Canonical ring map from a terminal object]
7001	  \label{def:term_ring_map}
7002	  \lean{PresheafOfModules.InternalHom.termRingMap}
7003	  \uses{def:presheaf_internal_hom_value}
7004	  For a presheaf of commutative rings \(R\) on a base category with terminal object
7005	  \(T\) and an object \(Y\), the unique morphism \(Y \to T\) induces the ring map
7006	  \(R(T) \to R(Y)\) along which a global scalar acts on the value at \(Y\).
7007	\end{definition}
7008	\begin{proof}
7009	  \uses{def:presheaf_internal_hom_value}
7010	  Proved directly in Lean, as \(R\) applied to the opposite of the terminal morphism.
7011	\end{proof}
7012	
7013	\begin{lemma}[Naturality of the terminal ring map]
7014	  \label{lem:term_ring_map_naturality}
7015	  \lean{PresheafOfModules.InternalHom.termRingMap_naturality}
7016	  \uses{def:term_ring_map}
7017	  The restriction map \(R(g) : R(X) \to R(Y)\) along \(g : X \to Y\) carries
7018	  \(\mathtt{termRingMap}_X\,f\) to \(\mathtt{termRingMap}_Y\,f\), so the images of a
7019	  global scalar \(f \in R(T)\) are compatible with restriction.
7020	\end{lemma}
7021	\begin{proof}
7022	  \uses{def:term_ring_map}
7023	  Proved directly in Lean, from uniqueness of morphisms into the terminal object and
7024	  functoriality of \(R\).
7025	\end{proof}
7026	
7027	\begin{lemma}[The terminal ring map at the terminal object is the identity]
7028	  \label{lem:term_ring_map_terminal}
7029	  \lean{PresheafOfModules.InternalHom.termRingMap_terminal}
7030	  \uses{def:term_ring_map}
7031	  At the terminal object itself the induced ring map \(R(T) \to R(T)\) is the
7032	  identity, since the unique \(T \to T\) is \(\mathrm{id}_T\).
7033	\end{lemma}
7034	\begin{proof}
7035	  \uses{def:term_ring_map}
7036	  Proved directly in Lean, using \(\mathtt{IsTerminal.hom\_ext}\) and
7037	  \(R.\mathtt{map\_id}\).
7038	\end{proof}
7039	
7040	\begin{definition}[Multiplication by a global scalar as an endomorphism]
7041	  \label{def:global_smul}
7042	  \lean{PresheafOfModules.InternalHom.globalSMul}
7043	  \uses{def:term_ring_map, lem:term_ring_map_naturality}
7044	  For \(f \in R(T)\), the endomorphism \(m_f^{N} : N \to N\) of a presheaf of modules
7045	  \(N\) that at each object \(Y\) is multiplication by \(\mathtt{termRingMap}_Y\,f \in
7046	  R(Y)\); its naturality is the heart of the global-scalar action on morphism modules.
7047	\end{definition}
7048	\begin{proof}
7049	  \uses{def:term_ring_map, lem:term_ring_map_naturality}
7050	  Proved directly in Lean: the naturality square commutes by
7051	  \(\mathtt{termRingMap\_naturality}\) and the semilinearity of the restriction maps of
7052	  \(N\).
7053	\end{proof}
7054	
7055	\begin{lemma}[Sectionwise action of the global-scalar endomorphism]
7056	  \label{lem:global_smul_hom_apply}
7057	  \lean{PresheafOfModules.InternalHom.globalSMul_hom_apply}
7058	  \uses{def:global_smul}
7059	  At an object \(Y\), \(m_f^{N}\) acts on a section as multiplication by
7060	  \(\mathtt{termRingMap}_Y\,f\).
7061	\end{lemma}
7062	\begin{proof}
7063	  \uses{def:global_smul}
7064	  Proved directly in Lean, by definitional unfolding.
7065	\end{proof}
7066	
7067	\begin{lemma}[The global-scalar endomorphism at one is the identity]
7068	  \label{lem:global_smul_one}
7069	  \lean{PresheafOfModules.InternalHom.globalSMul_one}
7070	  \uses{def:global_smul}
7071	  \(m_1^{N} = \mathrm{id}_N\).
7072	\end{lemma}
7073	\begin{proof}
7074	  \uses{def:global_smul}
7075	  Proved directly in Lean, from \(\mathtt{map\_one}\) and \(1 \cdot s = s\).
