7077	
7078	\begin{lemma}[The global-scalar endomorphism at zero is zero]
7079	  \label{lem:global_smul_zero}
7080	  \lean{PresheafOfModules.InternalHom.globalSMul_zero}
7081	  \uses{def:global_smul}
7082	  \(m_0^{N} = 0\).
7083	\end{lemma}
7084	\begin{proof}
