7089	\begin{lemma}[Additivity of the global-scalar endomorphism]
7090	  \label{lem:global_smul_add}
7091	  \lean{PresheafOfModules.InternalHom.globalSMul_add}
7092	  \uses{def:global_smul}
7093	  \(m_{f+g}^{N} = m_f^{N} + m_g^{N}\).
7094	\end{lemma}
7095	\begin{proof}
7096	  \uses{def:global_smul}
7097	  Proved directly in Lean, from \(\mathtt{map\_add}\) and \((f+g) \cdot s = f \cdot s +
7098	  g \cdot s\).
7099	\end{proof}
7100	
7101	\begin{lemma}[Multiplicativity of the global-scalar endomorphism]
7102	  \label{lem:global_smul_mul}
7103	  \lean{PresheafOfModules.InternalHom.globalSMul_mul}
7104	  \uses{def:global_smul}
7105	  \(m_{fg}^{N} = m_g^{N} \circ m_f^{N}\): ring multiplication becomes composition,
7106	  the order reversed because the action is by post-composition.
7107	\end{lemma}
7108	\begin{proof}
